SELECT avg_premium_wisconsin
FROM annual_premiums
WHERE year = 2020;

SELECT AVG(total_premiums_collected) AS average_total_premiums
FROM annual_premiums
WHERE market_id = 1;

SELECT year, avg_premium_wisconsin
FROM annual_premiums
ORDER BY year ASC;

SELECT AVG(yearly_change) AS avg_yearly_change
FROM premium_trends
WHERE market_id = 0 AND year = 2021;

SELECT product_id, AVG(avg_premium) AS avg_premium
FROM premium_trends
GROUP BY product_id;

SELECT product_id, AVG(yearly_change_wisconsin) AS avg_yearly_change_wisconsin
FROM annual_premiums
GROUP BY product_id;
